args.sparql:
SELECT DISTINCT ?player ?playerLabel
WHERE {
  ?team wdt:P154 wd:Q16896 .
  ?player p:P54 ?statement .
  ?statement ps:P54 ?team .
  ?statement pq:P39 wd:Q4159 .
  ?superbowl wdt:P31 wd:Q422841 .
  ?player wdt:P706 ?superbowl .
  OPTIONAL { ?player rdfs:label ?playerLabel . FILTER (lang(?playerLabel) = "en") }
}

SELECT DISTINCT ?player ?playerLabel
WHERE {
  ?superbowl wdt:P31 wd:Q422841 .
  ?superbowl wdt:P915 ?team .
  ?team wdt:P154 wd:Q16896 .
  ?player p:P54 ?statement .
  ?statement ps:P54 ?team .
  ?statement pq:P39 wd:Q4159 .
  OPTIONAL { ?player rdfs:label ?playerLabel . FILTER (lang(?playerLabel) = "en") }
}

SELECT DISTINCT ?player ?playerLabel
WHERE {
  ?player wdt:P39 wd:Q4159 .
  ?player wdt:P54 ?team .
  ?team wdt:P154 wd:Q16896 .
  ?player wdt:P706 ?superbowl .
  ?superbowl wdt:P31 wd:Q422841 .
  OPTIONAL { ?player rdfs:label ?playerLabel . FILTER (lang(?playerLabel) = "en") }
}
